import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";
import gemBackground from "../assets/background.png";

function Result() {
  const navigate = useNavigate();
  const location = useLocation();
  const {
    gem_prediction,
    gem_confidence,
    shape_prediction,
    shape_confidence,
    image,
    show_shape,
  } = location.state || {};

  const gemConfidencePercent   = (gem_confidence * 100)?.toFixed(1) ?? "—";
  const shapeConfidencePercent = show_shape ? (shape_confidence * 100)?.toFixed(1) ?? "—" : null;

  return (
    <>
      <Topnav />

      <main
        className="min-h-[70vh] flex items-center justify-center py-6 px-4 bg-cover bg-center bg-no-repeat"
        style={{
          backgroundImage: `url(${gemBackground})`,
          backgroundColor: 'rgba(0, 0, 0, 0.2)',
          backgroundBlendMode: 'multiply',
        }}
      >
        <div className="w-full max-w-md bg-white/92 backdrop-blur-sm rounded-xl shadow-lg p-5 sm:p-6 text-center border border-gray-200/40">
          <h1 className="text-xl sm:text-2xl font-bold text-gray-800 mb-4">
            Analysis Result
          </h1>

          {image && (
            <div className="mb-4">
              <img
                src={URL.createObjectURL(image)}
                alt={gem_prediction || "Gem"}
                className="w-40 h-40 sm:w-48 sm:h-48 mx-auto rounded-full object-cover shadow-md border-2 border-blue-100"
              />
            </div>
          )}

          <div className="space-y-4 text-sm sm:text-base">
            <div>
              <p className="text-gray-600">Gem</p>
              <p className="text-xl sm:text-2xl font-bold text-blue-700 mt-0.5">
                {gem_prediction || "Unknown"}
              </p>
              <p className="text-gray-600 mt-0.5">
                {gemConfidencePercent}%
              </p>
            </div>

            {show_shape && shape_prediction && (
              <div>
                <p className="text-gray-600">Shape / Cut</p>
                <p className="text-xl sm:text-2xl font-bold text-blue-700 capitalize mt-0.5">
                  {shape_prediction}
                </p>
                <p className="text-gray-600 mt-0.5">
                  {shapeConfidencePercent}%
                </p>
              </div>
            )}
          </div>

          <button
            onClick={() => navigate("/imageuploader")}
            className="mt-6 w-full max-w-xs mx-auto block py-2.5 px-6 bg-blue-600 hover:bg-blue-700 text-white text-sm sm:text-base font-medium rounded-full shadow-sm transition"
          >
            Analyze Another
          </button>
        </div>
      </main>

      <Footer />
    </>
  );
}

export default Result;
